import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.Crpw6aS5.js";const s=JSON.parse('{"title":"本·格雷厄姆（Ben Graham）","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/本·格雷厄姆.md","filePath":"04_people/本·格雷厄姆.md"}'),o={name:"04_people/本·格雷厄姆.md"};function h(i,t,d,u,n,q){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="本·格雷厄姆-ben-graham" tabindex="-1">本·格雷厄姆（Ben Graham） <a class="header-anchor" href="#本·格雷厄姆-ben-graham" aria-label="Permalink to &quot;本·格雷厄姆（Ben Graham）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>全名</td><td>Benjamin Graham</td></tr><tr><td>出生</td><td>1894年</td></tr><tr><td>逝世</td><td>1976年</td></tr><tr><td>职业</td><td>投资者、教授、作家</td></tr><tr><td>称号</td><td>&quot;价值投资之父&quot;、&quot;证券分析之父&quot;</td></tr></tbody></table><h2 id="核心贡献" tabindex="-1">核心贡献 <a class="header-anchor" href="#核心贡献" aria-label="Permalink to &quot;核心贡献&quot;">​</a></h2><h3 id="投资理论" tabindex="-1">投资理论 <a class="header-anchor" href="#投资理论" aria-label="Permalink to &quot;投资理论&quot;">​</a></h3><ol><li><p><strong>《证券分析》</strong>（1934年，与David Dodd合著）</p><ul><li>现代证券分析奠基之作</li><li>提出&quot;安全边际&quot;概念</li></ul></li><li><p><strong>《聪明的投资者》</strong>（1949年）</p><ul><li>巴菲特称&quot;最好的投资书&quot;</li><li>提出&quot;市场先生&quot;比喻</li></ul></li></ol><h3 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>含义</th></tr></thead><tbody><tr><td>安全边际</td><td>买入价格显著低于内在价值</td></tr><tr><td>市场先生</td><td>市场是服务你的伙伴，不是指导你的导师</td></tr><tr><td>内在价值</td><td>企业真实价值vs市场价格</td></tr></tbody></table><h2 id="与巴菲特关系" tabindex="-1">与巴菲特关系 <a class="header-anchor" href="#与巴菲特关系" aria-label="Permalink to &quot;与巴菲特关系&quot;">​</a></h2><h3 id="师生关系" tabindex="-1">师生关系 <a class="header-anchor" href="#师生关系" aria-label="Permalink to &quot;师生关系&quot;">​</a></h3><ul><li>1950年：巴菲特在哥伦比亚大学师从格雷厄姆</li><li>1954-1956年：巴菲特在格雷厄姆-纽曼公司工作</li><li>格雷厄姆是巴菲特投资思想的奠基人</li></ul><h3 id="思想传承" tabindex="-1">思想传承 <a class="header-anchor" href="#思想传承" aria-label="Permalink to &quot;思想传承&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格雷厄姆教导</th><th>巴菲特实践</th></tr></thead><tbody><tr><td>安全边际</td><td>所有投资决策核心原则</td></tr><tr><td>市场先生</td><td>独立判断，不被市场情绪影响</td></tr><tr><td>烟蒂投资</td><td>早期沿用，后期转向质量投资</td></tr></tbody></table><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><h3 id="_1985年股东信" tabindex="-1">1985年股东信 <a class="header-anchor" href="#_1985年股东信" aria-label="Permalink to &quot;1985年股东信&quot;">​</a></h3><blockquote><p>&quot;我的投资哲学85%来自格雷厄姆，15%来自费雪。&quot;</p></blockquote><h3 id="_1987年股东信" tabindex="-1">1987年股东信 <a class="header-anchor" href="#_1987年股东信" aria-label="Permalink to &quot;1987年股东信&quot;">​</a></h3><blockquote><p>&quot;格雷厄姆教导我：市场先生是你的仆人，不是你的导师。&quot;</p></blockquote><h3 id="多次提及" tabindex="-1">多次提及 <a class="header-anchor" href="#多次提及" aria-label="Permalink to &quot;多次提及&quot;">​</a></h3><blockquote><p>&quot;《聪明的投资者》是我读过的最好的投资书。第8章和第20章是投资者必读。&quot;</p></blockquote><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;短期看，市场是投票机；长期看，市场是称重机。&quot;</p></blockquote><blockquote><p>&quot;投资者最大的敌人很可能就是他自己。&quot;</p></blockquote><blockquote><p>&quot;在股市中，要想在预测中赚钱，你必须预测预测者的预测。&quot;</p></blockquote><h2 id="影响力" tabindex="-1">影响力 <a class="header-anchor" href="#影响力" aria-label="Permalink to &quot;影响力&quot;">​</a></h2><ul><li>培养了一代价值投资者（巴菲特、沃尔特·施洛斯、约翰·博格等）</li><li>奠定了现代证券分析职业基础</li><li>&quot;安全边际&quot;成为价值投资核心原则</li></ul><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1984, 1985, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./沃伦·巴菲特.html">沃伦·巴菲特</a> - 学生</li><li><a href="./../02_主题索引/投资哲学/安全边际.html">安全边际</a> - 核心概念</li><li><a href="./../02_主题索引/投资哲学/市场先生.html">市场先生</a> - 经典比喻</li></ul><hr><p><em>最后更新：2026-04-09</em></p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/1984年/翻译.html">1984年</a></li><li><a href="./../01_letters/1985年/翻译.html">1985年</a></li><li><a href="./../01_letters/1993年/翻译.html">1993年</a></li><li><a href="./../01_letters/1995年/翻译.html">1995年</a></li><li><a href="./../01_letters/2001年/翻译.html">2001年</a></li><li><a href="./../01_letters/2011年/翻译.html">2011年</a></li><li><a href="./../01_letters/2013年/翻译.html">2013年</a></li></ul>',34)])])}const c=a(o,[["render",h]]);export{s as __pageData,c as default};
